  ('dietitian-moex-11392', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列有關創傷弧菌（Vibrio vulnificus）之描述，不正確者為： 革蘭氏陰性菌  造成蜂窩性組織炎  對肝病患者敏感  媒介食品主要為生牛肉', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "66a40bb85066", "answer_pdf_sha1": "ef42fcd1b56b", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
